import { memo, useCallback, useLayoutEffect, useMemo, useRef } from 'react';
import { Type } from 'lucide-react';
import '@/tools/video-editor/components/TimelineEditor/timeline-overrides.css';
import { ClipAction } from '@/tools/video-editor/components/TimelineEditor/ClipAction';
import { DropIndicator } from '@/tools/video-editor/components/TimelineEditor/DropIndicator';
import { TimelineCanvas } from '@/tools/video-editor/components/TimelineEditor/TimelineCanvas';
import { TrackLabel } from '@/tools/video-editor/components/TimelineEditor/TrackLabel';
import { ROW_HEIGHT, TIMELINE_START_LEFT } from '@/tools/video-editor/lib/coordinate-utils';
import { useTimelineChromeContext } from '@/tools/video-editor/contexts/TimelineChromeContext';
import { useTimelineEditorContext } from '@/tools/video-editor/contexts/TimelineEditorContext';
import { useClipDrag } from '@/tools/video-editor/hooks/useClipDrag';
import { useMarqueeSelect } from '@/tools/video-editor/hooks/useMarqueeSelect';
import type { TimelineAction } from '@/tools/video-editor/types/timeline-canvas';

function TimelineEditorComponent() {
  const chrome = useTimelineChromeContext();
  const {
    data,
    resolvedConfig,
    timelineRef,
    timelineWrapperRef,
    dataRef,
    applyTimelineEdit,
    moveClipToRow,
    createTrackAndMoveClip,
    selectClip,
    selectClips,
    addToSelection,
    clearSelection,
    isClipSelected,
    primaryClipId,
    selectedClipIds,
    selectedClipIdsRef,
    setSelectedTrackId,
    scale,
    scaleWidth,
    coordinator,
    indicatorRef,
    editAreaRef,
    selectedTrackId,
    handleTrackPopoverChange,
    handleReorderTrack,
    handleRemoveTrack,
    handleSplitClipAtTime,
    handleSplitClipsAtPlayhead,
    handleDeleteClips,
    handleDeleteClip,
    handleToggleMuteClips,
    onCursorDrag,
    onClickTimeArea,
    onActionResizeStart,
    onActionResizeEnd,
    onTimelineDragOver,
    onTimelineDragLeave,
    onTimelineDrop,
    onDoubleClickAsset,
  } = useTimelineEditorContext();
  const trackListRef = useRef<HTMLDivElement>(null);

  // useClipDrag handles all internal clip drag interactions (horizontal moves,
  // cross-track moves, and new-track creation) using the same fixed-position
  // drop indicators as external HTML5 drag-drop.
  const { dragSessionRef } = useClipDrag({
    timelineWrapperRef,
    dataRef,
    moveClipToRow,
    createTrackAndMoveClip,
    applyTimelineEdit,
    selectClip,
    selectClips,
    selectedClipIdsRef,
    coordinator,
    rowHeight: ROW_HEIGHT,
    scale,
    scaleWidth,
    startLeft: TIMELINE_START_LEFT,
  });

  const { marqueeRect, onPointerDown: onMarqueePointerDown } = useMarqueeSelect({
    editAreaRef,
    dragSessionRef,
    selectClips,
    addToSelection,
    clearSelection,
  });

  useLayoutEffect(() => {
    const wrapper = timelineWrapperRef.current;
    const nextEditArea = wrapper?.querySelector<HTMLElement>('.timeline-canvas-edit-area') ?? null;
    editAreaRef.current = nextEditArea;

    return () => {
      if (editAreaRef.current === nextEditArea) {
        editAreaRef.current = null;
      }
    };
  }, [data, editAreaRef, timelineWrapperRef]);

  const scaleCount = useMemo(() => {
    if (!data) {
      return 1;
    }

    let maxEnd = 0;
    for (const row of data.rows) {
      for (const action of row.actions) {
        maxEnd = Math.max(maxEnd, action.end);
      }
    }

    return Math.ceil((maxEnd + 20) / scale) + 1;
  }, [data, scale]);

  const thumbnailMap = useMemo<Record<string, string>>(() => {
    if (!resolvedConfig) {
      return {};
    }

    return resolvedConfig.clips.reduce<Record<string, string>>((acc, clip) => {
      if (clip.clipType === 'text' || !clip.assetEntry?.type?.startsWith('image')) {
        return acc;
      }

      acc[clip.id] = clip.assetEntry.src;
      return acc;
    }, {});
  }, [resolvedConfig]);

  const handleClipSelect = useCallback((clipId: string, trackId: string) => {
    selectClip(clipId);
    setSelectedTrackId(trackId);
  }, [selectClip, setSelectedTrackId]);

  const pixelsPerSecond = scaleWidth / scale;

  const clientXToTime = useCallback((clientX: number): number => {
    const wrapper = timelineWrapperRef.current;
    if (!wrapper) return 0;
    const editArea = wrapper.querySelector<HTMLElement>('.timeline-canvas-edit-area');
    const grid = editArea;
    const rect = (editArea ?? wrapper).getBoundingClientRect();
    const scrollLeft = grid?.scrollLeft ?? 0;
    return Math.max(0, (clientX - rect.left + scrollLeft - TIMELINE_START_LEFT) / pixelsPerSecond);
  }, [pixelsPerSecond, timelineWrapperRef]);

  const handleSplitClipHere = useCallback((clipId: string, clientX: number) => {
    const time = clientXToTime(clientX);
    handleSplitClipAtTime(clipId, time);
  }, [clientXToTime, handleSplitClipAtTime]);

  const getActionRender = useCallback((action: TimelineAction) => {
    const clipMeta = data?.meta[action.id];
    if (!clipMeta) {
      return null;
    }

    const clipWidthPx = (action.end - action.start) * pixelsPerSecond;
    const thumbnailSrc = clipWidthPx >= 40 ? thumbnailMap[action.id] : undefined;

    return (
      <ClipAction
        action={action}
        clipMeta={clipMeta}
        isSelected={isClipSelected(action.id)}
        isPrimary={primaryClipId === action.id}
        selectedClipIds={[...selectedClipIds]}
        thumbnailSrc={thumbnailSrc}
        onSelect={handleClipSelect}
        onDoubleClickAsset={onDoubleClickAsset}
        onSplitHere={handleSplitClipHere}
        onSplitClipsAtPlayhead={handleSplitClipsAtPlayhead}
        onDeleteClips={handleDeleteClips}
        onDeleteClip={handleDeleteClip}
        onToggleMuteClips={handleToggleMuteClips}
      />
    );
  }, [
    data,
    handleClipSelect,
    handleDeleteClip,
    handleDeleteClips,
    handleSplitClipHere,
    handleSplitClipsAtPlayhead,
    handleToggleMuteClips,
    isClipSelected,
    onDoubleClickAsset,
    pixelsPerSecond,
    primaryClipId,
    selectedClipIds,
    thumbnailMap,
  ]);

  const kindCountMap = useMemo(() => {
    if (!data) {
      return {} as Record<string, number>;
    }

    return data.tracks.reduce<Record<string, number>>((counts, track) => {
      counts[track.kind] = (counts[track.kind] ?? 0) + 1;
      return counts;
    }, {});
  }, [data]);

  if (!data) {
    return null;
  }

  return (
    <div className="flex h-full overflow-hidden rounded-xl border border-border bg-card/80">
      <div
        ref={trackListRef}
        className="flex w-36 shrink-0 flex-col overflow-y-auto border-r border-border pt-[30px]"
        onScroll={(event) => {
          timelineRef.current?.setScrollTop(event.currentTarget.scrollTop);
        }}
      >
        {data.tracks.map((track, index) => {
          const row = data.rows[index];
          return (
            <TrackLabel
              key={track.id}
              track={track}
              isSelected={selectedTrackId === track.id}
              trackCount={data.tracks.length}
              trackIndex={index}
              sameKindCount={kindCountMap[track.kind] ?? 0}
              hasClips={Boolean(row && row.actions.length > 0)}
              onSelect={setSelectedTrackId}
              onChange={handleTrackPopoverChange}
              onReorder={handleReorderTrack}
              onRemove={handleRemoveTrack}
            />
          );
        })}
      </div>
      <div
        ref={timelineWrapperRef}
        className="timeline-wrapper relative min-w-0 flex-1 overflow-hidden"
        onDragOver={onTimelineDragOver}
        onDragLeave={onTimelineDragLeave}
        onDrop={onTimelineDrop}
      >
        <TimelineCanvas
          ref={timelineRef}
          rows={data.rows}
          scale={scale}
          scaleWidth={scaleWidth}
          scaleSplitCount={5}
          startLeft={TIMELINE_START_LEFT}
          rowHeight={ROW_HEIGHT}
          minScaleCount={scaleCount}
          maxScaleCount={scaleCount}
          getActionRender={getActionRender}
          onCursorDrag={onCursorDrag}
          onClickTimeArea={onClickTimeArea}
          onActionResizeStart={onActionResizeStart}
          onActionResizeEnd={onActionResizeEnd}
          marqueeRect={marqueeRect}
          onEditAreaPointerDown={onMarqueePointerDown}
          trackLabelRef={trackListRef}
          onAddText={chrome.handleAddText}
        />
        <DropIndicator ref={indicatorRef} editAreaRef={editAreaRef} />
        <div className="pointer-events-none absolute inset-0 z-40">
          <button
            type="button"
            className="pointer-events-auto absolute bottom-3 left-3 flex h-7 w-7 items-center justify-center rounded-md border border-border/70 bg-card/90 text-muted-foreground shadow-sm backdrop-blur-sm transition-colors hover:bg-accent hover:text-foreground"
            onClick={chrome.handleAddText}
            title="Add text clip"
          >
            <Type className="h-3.5 w-3.5" />
          </button>
        </div>
      </div>
    </div>
  );
}

export const TimelineEditor = memo(TimelineEditorComponent);

import { useCallback, useEffect, useRef, useState } from 'react';
import { ArrowDown, ArrowUp, Check, Settings, Trash2, Video, Volume2 } from 'lucide-react';
import { Button } from '@/shared/components/ui/button';
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle, DialogTrigger } from '@/shared/components/ui/dialog';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/shared/components/ui/select';
import { Slider } from '@/shared/components/ui/slider';
import { cn } from '@/shared/components/ui/contracts/cn';
import type { TrackBlendMode, TrackDefinition, TrackFit } from '@/tools/video-editor/types';

interface TrackLabelProps {
  track: TrackDefinition;
  isSelected: boolean;
  trackCount: number;
  trackIndex: number;
  sameKindCount: number;
  hasClips: boolean;
  onSelect: (trackId: string) => void;
  onChange: (trackId: string, patch: Partial<TrackDefinition>) => void;
  onReorder: (trackId: string, direction: -1 | 1) => void;
  onRemove: (trackId: string) => void;
}

const FIT_OPTIONS: { value: TrackFit; label: string }[] = [
  { value: 'cover', label: 'Cover' },
  { value: 'contain', label: 'Contain' },
  { value: 'manual', label: 'Manual' },
];

const BLEND_OPTIONS: { value: TrackBlendMode; label: string }[] = [
  { value: 'normal', label: 'Normal' },
  { value: 'multiply', label: 'Multiply' },
  { value: 'screen', label: 'Screen' },
  { value: 'overlay', label: 'Overlay' },
  { value: 'darken', label: 'Darken' },
  { value: 'lighten', label: 'Lighten' },
  { value: 'color-dodge', label: 'Color Dodge' },
  { value: 'color-burn', label: 'Color Burn' },
  { value: 'soft-light', label: 'Soft Light' },
  { value: 'hard-light', label: 'Hard Light' },
];

function FieldLabel({ children }: { children: React.ReactNode }) {
  return <div className="text-[11px] font-medium text-muted-foreground">{children}</div>;
}

export function TrackLabel({
  track,
  isSelected,
  trackCount,
  trackIndex,
  sameKindCount,
  hasClips,
  onSelect,
  onChange,
  onReorder,
  onRemove,
}: TrackLabelProps) {
  const [confirmingDelete, setConfirmingDelete] = useState(false);
  const confirmTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    if (!confirmingDelete) return;
    confirmTimerRef.current = setTimeout(() => setConfirmingDelete(false), 2000);
    return () => { if (confirmTimerRef.current) clearTimeout(confirmTimerRef.current); };
  }, [confirmingDelete]);

  const handleRemoveClick = useCallback((event: React.MouseEvent) => {
    event.stopPropagation();
    if (!hasClips) {
      onRemove(track.id);
      return;
    }
    if (confirmingDelete) {
      setConfirmingDelete(false);
      onRemove(track.id);
    } else {
      setConfirmingDelete(true);
    }
  }, [confirmingDelete, hasClips, onRemove, track.id]);

  return (
    <div
      className={cn(
        'group relative flex h-9 items-center gap-1 border-b border-border px-2 text-xs text-foreground',
        isSelected ? 'bg-accent/70' : 'bg-card/60 hover:bg-accent/50',
      )}
      onClick={() => onSelect(track.id)}
    >
      <span className="shrink-0 text-muted-foreground">
        {track.kind === 'visual' ? <Video className="h-3.5 w-3.5" /> : <Volume2 className="h-3.5 w-3.5" />}
      </span>

      {/* Full label shown at rest, fades out on hover */}
      <span className="min-w-0 flex-1 truncate transition-opacity group-hover:opacity-0">
        {track.label}
      </span>

      {/* Editable input + action buttons on hover */}
      <div className="absolute inset-0 flex items-center gap-1 px-2 opacity-0 transition-opacity group-hover:opacity-100">
        <span className="w-[18px] shrink-0" />
        <input
          className="min-w-0 flex-1 bg-transparent text-xs outline-none"
          value={track.label}
          onChange={(event) => onChange(track.id, { label: event.target.value })}
          onClick={(event) => event.stopPropagation()}
        />
        <div className="flex shrink-0 items-center">
          <Dialog>
            <DialogTrigger asChild>
              <Button
                type="button"
                variant="ghost"
                size="icon"
                className="h-6 w-6 text-muted-foreground"
                title="Track defaults"
                onClick={(event) => event.stopPropagation()}
              >
                <Settings className="h-3.5 w-3.5" />
              </Button>
            </DialogTrigger>
            <DialogContent className="max-w-sm" onClick={(e) => e.stopPropagation()}>
              <DialogHeader>
                <DialogTitle>{track.label} ‚Äî Track Defaults</DialogTitle>
                <DialogDescription>
                  New items dropped on this track will inherit these settings.
                </DialogDescription>
              </DialogHeader>
              <div className="space-y-4 pt-2">
                {track.kind === 'visual' && (
                  <>
                    <div className="space-y-1.5">
                      <FieldLabel>Fit</FieldLabel>
                      <Select
                        value={track.fit ?? 'contain'}
                        onValueChange={(value) => onChange(track.id, { fit: value as TrackFit })}
                      >
                        <SelectTrigger className="h-8 text-xs"><SelectValue /></SelectTrigger>
                        <SelectContent>
                          {FIT_OPTIONS.map((opt) => (
                            <SelectItem key={opt.value} value={opt.value}>{opt.label}</SelectItem>
                          ))}
                        </SelectContent>
                      </Select>
                    </div>
                    <div className="space-y-1.5">
                      <FieldLabel>Scale ({((track.scale ?? 1) * 100).toFixed(0)}%)</FieldLabel>
                      <Slider
                        value={[track.scale ?? 1]}
                        min={0.1}
                        max={2}
                        step={0.05}
                        onValueChange={(v) => onChange(track.id, { scale: v[0] })}
                      />
                    </div>
                    <div className="space-y-1.5">
                      <FieldLabel>Opacity ({((track.opacity ?? 1) * 100).toFixed(0)}%)</FieldLabel>
                      <Slider
                        value={[track.opacity ?? 1]}
                        min={0}
                        max={1}
                        step={0.05}
                        onValueChange={(v) => onChange(track.id, { opacity: v[0] })}
                      />
                    </div>
                    <div className="space-y-1.5">
                      <FieldLabel>Blend Mode</FieldLabel>
                      <Select
                        value={track.blendMode ?? 'normal'}
                        onValueChange={(value) => onChange(track.id, { blendMode: value as TrackBlendMode })}
                      >
                        <SelectTrigger className="h-8 text-xs"><SelectValue /></SelectTrigger>
                        <SelectContent>
                          {BLEND_OPTIONS.map((opt) => (
                            <SelectItem key={opt.value} value={opt.value}>{opt.label}</SelectItem>
                          ))}
                        </SelectContent>
                      </Select>
                    </div>
                  </>
                )}
                {track.kind === 'audio' && (
                  <div className="space-y-1.5">
                    <FieldLabel>Default Volume ({((track.opacity ?? 1) * 100).toFixed(0)}%)</FieldLabel>
                    <Slider
                      value={[track.opacity ?? 1]}
                      min={0}
                      max={1}
                      step={0.05}
                      onValueChange={(v) => onChange(track.id, { opacity: v[0] })}
                    />
                  </div>
                )}
              </div>
            </DialogContent>
          </Dialog>
          <Button
            type="button"
            variant="ghost"
            size="icon"
            className="h-6 w-6 text-muted-foreground"
            disabled={trackIndex === 0 || sameKindCount <= 1}
            onClick={(event) => {
              event.stopPropagation();
              onReorder(track.id, -1);
            }}
          >
            <ArrowUp className="h-3.5 w-3.5" />
          </Button>
          <Button
            type="button"
            variant="ghost"
            size="icon"
            className="h-6 w-6 text-muted-foreground"
            disabled={trackIndex >= trackCount - 1 || sameKindCount <= 1}
            onClick={(event) => {
              event.stopPropagation();
              onReorder(track.id, 1);
            }}
          >
            <ArrowDown className="h-3.5 w-3.5" />
          </Button>
          <Button
            type="button"
            variant="ghost"
            size="icon"
            className={cn('h-6 w-6', confirmingDelete ? 'text-destructive hover:text-destructive' : 'text-muted-foreground')}
            title={confirmingDelete ? 'Click again to confirm deletion' : 'Remove track'}
            onClick={handleRemoveClick}
          >
            {confirmingDelete ? <Check className="h-3.5 w-3.5" /> : <Trash2 className="h-3.5 w-3.5" />}
          </Button>
        </div>
      </div>
    </div>
  );
}

  }

  for (const move of plannedMoves) {
    moveClipToRow(move.clipId, move.targetRowId);
  }

  const primaryMove = selectedClipId
    ? plannedMoves.find((move) => move.clipId === selectedClipId)
    : plannedMoves[0];
  if (primaryMove) {
    setSelectedTrackId(primaryMove.targetRowId);
  }
}, [dataRef, moveClipToRow, selectedClipId, setSelectedTrackId]);

const handleAddTrack = useCallback((kind: TrackKind) => {
  if (!resolvedConfig) {
    return;
  }

  const nextResolvedConfig = addTrack(resolvedConfig, kind);
  const nextTrack = nextResolvedConfig.tracks[nextResolvedConfig.tracks.length - 1] ?? null;
  applyResolvedConfigEdit(nextResolvedConfig, { selectedTrackId: nextTrack?.id ?? null });
}, [applyResolvedConfigEdit, resolvedConfig]);

const handleTrackPopoverChange = useCallback((trackId: string, patch: Partial<TrackDefinition>) => {
  if (!resolvedConfig) {
    return;
  }

  const nextConfig = {
    ...resolvedConfig,
    tracks: resolvedConfig.tracks.map((track) => (track.id === trackId ? { ...track, ...patch } : track)),
  };
  applyResolvedConfigEdit(nextConfig, { selectedTrackId: trackId });
}, [applyResolvedConfigEdit, resolvedConfig]);

const handleReorderTrack = useCallback((trackId: string, direction: -1 | 1) => {
  if (!resolvedConfig) {
    return;
  }

  const index = resolvedConfig.tracks.findIndex((track) => track.id === trackId);
  if (index < 0) {
    return;
  }

  const targetIndex = index + direction;
  if (targetIndex < 0 || targetIndex >= resolvedConfig.tracks.length) {
    return;
  }

  if (resolvedConfig.tracks[index].kind !== resolvedConfig.tracks[targetIndex].kind) {
    return;
  }

  const nextTracks = [...resolvedConfig.tracks];
  [nextTracks[index], nextTracks[targetIndex]] = [nextTracks[targetIndex], nextTracks[index]];
  applyResolvedConfigEdit({ ...resolvedConfig, tracks: nextTracks }, { selectedTrackId: trackId });
}, [applyResolvedConfigEdit, resolvedConfig]);

const handleRemoveTrack = useCallback((trackId: string) => {
  if (!resolvedConfig) {
    return;
  }

  const track = resolvedConfig.tracks.find((entry) => entry.id === trackId);
  if (!track) {
    return;
  }

  const sameKind = resolvedConfig.tracks.filter((entry) => entry.kind === track.kind);
  if (sameKind.length <= 1) {
    return;
  }

  const nextConfig = {
    ...resolvedConfig,
    tracks: resolvedConfig.tracks.filter((entry) => entry.id !== trackId),
    clips: resolvedConfig.clips.filter((clip) => clip.track !== trackId),
  };
  applyResolvedConfigEdit(nextConfig, { selectedTrackId: null });
}, [applyResolvedConfigEdit, resolvedConfig]);

const unusedTrackCount = useMemo(() => {
  if (!resolvedConfig) {
    return 0;
  }

  const tracksWithClips = new Set(resolvedConfig.clips.map((clip) => clip.track));
  const defaultTrackIds = new Set(DEFAULT_VIDEO_TRACKS.map((track) => track.id));

