import { describe, expect, it } from 'vitest';
import { reorderTracksByDirection } from '@/tools/video-editor/hooks/useTimelineTrackManagement';
import type { TrackDefinition, TrackKind } from '@/tools/video-editor/types';

function makeTrack(id: string, kind: TrackKind): TrackDefinition {
  return {
    id,
    kind,
    label: id,
  };
}

function getTrackOrder(tracks: TrackDefinition[]): string[] {
  return tracks.map((track) => track.id);
}

describe('reorderTracksByDirection', () => {
  it('handles mixed-kind boundaries without crossing kinds', () => {
    const tracks = [
      makeTrack('V1', 'visual'),
      makeTrack('V2', 'visual'),
      makeTrack('A1', 'audio'),
      makeTrack('A2', 'audio'),
    ];

    expect(getTrackOrder(reorderTracksByDirection(tracks, 'V2', 1))).toEqual(['V1', 'V2', 'A1', 'A2']);
    expect(getTrackOrder(reorderTracksByDirection(tracks, 'A1', -1))).toEqual(['V1', 'V2', 'A1', 'A2']);
    expect(getTrackOrder(reorderTracksByDirection(tracks, 'A1', 1))).toEqual(['V1', 'V2', 'A2', 'A1']);
    expect(getTrackOrder(reorderTracksByDirection(tracks, 'V1', 1))).toEqual(['V2', 'V1', 'A1', 'A2']);
  });

  it('no-ops when each kind has only one track', () => {
    const tracks = [
      makeTrack('V1', 'visual'),
      makeTrack('A1', 'audio'),
    ];

    expect(getTrackOrder(reorderTracksByDirection(tracks, 'V1', -1))).toEqual(['V1', 'A1']);
    expect(getTrackOrder(reorderTracksByDirection(tracks, 'V1', 1))).toEqual(['V1', 'A1']);
    expect(getTrackOrder(reorderTracksByDirection(tracks, 'A1', -1))).toEqual(['V1', 'A1']);
    expect(getTrackOrder(reorderTracksByDirection(tracks, 'A1', 1))).toEqual(['V1', 'A1']);
  });

  it('reorders normally when all tracks share the same kind', () => {
    const tracks = [
      makeTrack('V1', 'visual'),
      makeTrack('V2', 'visual'),
      makeTrack('V3', 'visual'),
    ];

    expect(getTrackOrder(reorderTracksByDirection(tracks, 'V1', 1))).toEqual(['V2', 'V1', 'V3']);
    expect(getTrackOrder(reorderTracksByDirection(tracks, 'V2', 1))).toEqual(['V1', 'V3', 'V2']);
    expect(getTrackOrder(reorderTracksByDirection(tracks, 'V3', -1))).toEqual(['V1', 'V3', 'V2']);
  });
});

export type TimelineEffect = {
  fade_in?: number;
  fade_out?: number;
};

export type TrackKind = 'visual' | 'audio';
export type TrackFit = 'cover' | 'contain' | 'manual';
export type TrackBlendMode =
  | 'normal'
  | 'multiply'
  | 'screen'
  | 'overlay'
  | 'darken'
  | 'lighten'
  | 'soft-light'
  | 'hard-light';
export type ClipType = 'media' | 'hold' | 'text';

export type TrackDefinition = {
  id: string;
  kind: TrackKind;
  label: string;
  scale?: number;
  fit?: TrackFit;
  opacity?: number;
  blendMode?: TrackBlendMode;
};

export type ClipEntrance = {
  type: string;
  duration: number;
};

export type ClipExit = {
  type: string;
  duration: number;
};

export type ClipContinuous = {
  type: string;
  intensity?: number;
};

export type ClipTransition = {
  type: string;
  duration: number;
};

export type TextAlignment = 'left' | 'center' | 'right';

export type TextClipData = {
  content: string;
  fontFamily?: string;
  fontSize?: number;
  color?: string;
  align?: TextAlignment;
  bold?: boolean;
  italic?: boolean;
};

export type TimelineClip = {
  id: string;
  at: number;
  track: string;
  clipType?: ClipType;
  asset?: string;
  from?: number;
  to?: number;
  speed?: number;
  hold?: number;
  volume?: number;
  x?: number;
  y?: number;
  width?: number;
  height?: number;
  cropTop?: number;
  cropBottom?: number;
  cropLeft?: number;
  cropRight?: number;
  opacity?: number;
  text?: TextClipData;
  entrance?: ClipEntrance;
  exit?: ClipExit;
  continuous?: ClipContinuous;
  transition?: ClipTransition;
  effects?: TimelineEffect[] | Record<string, number>;
};

export type TimelineOutput = {
  resolution: string;
  fps: number;
  file: string;
  background?: string | null;
  background_scale?: number | null;
};

export type CustomEffectEntry = {
  code: string;
  category?: 'entrance' | 'exit' | 'continuous';
};

export type TimelineConfig = {
  output: TimelineOutput;
  clips: TimelineClip[];
  tracks?: TrackDefinition[];
  customEffects?: Record<string, CustomEffectEntry>;
};

export type AssetRegistryEntry = {
  file: string;
  type?: string;
  duration?: number;
  resolution?: string;
  fps?: number;
  generationId?: string;
  variantId?: string;
};

export type AssetRegistry = {
  assets: Record<string, AssetRegistryEntry>;
};

export type ResolvedAssetRegistryEntry = AssetRegistryEntry & {
  src: string;
};

export type ResolvedTimelineClip = TimelineClip & {
  assetEntry?: ResolvedAssetRegistryEntry;
};

export type ResolvedTimelineConfig = {
  output: TimelineOutput;
  tracks: TrackDefinition[];
  clips: ResolvedTimelineClip[];
  registry: Record<string, ResolvedAssetRegistryEntry>;
};

export type TimelineCompositionProps = {
  config?: ResolvedTimelineConfig;
  preview?: boolean;
};

const sortTracksByKind = (tracks: TrackDefinition[]): TrackDefinition[] => {
  const visual = tracks.filter((track) => track.kind === 'visual');
  const audio = tracks.filter((track) => track.kind === 'audio');
  return [...visual, ...audio];
};

export const buildTimelineData = async (
  config: TimelineConfig,
  registry: AssetRegistry,
  urlResolver?: UrlResolver,
  configVersion = 1,
): Promise<TimelineData> => {
  const migratedConfig = migrateToFlatTracks(config);
  migratedConfig.tracks = sortTracksByKind(migratedConfig.tracks ?? []);
  const resolvedConfig = await resolveTimelineConfig(migratedConfig, registry, urlResolver);
  const rowData = configToRows(migratedConfig);

  return {
    config: migratedConfig,
    configVersion,
    registry,
    resolvedConfig,
    rows: rowData.rows,
    meta: rowData.meta,
    effects: rowData.effects,
    assetMap: buildAssetMap(registry),
    output: { ...migratedConfig.output },
    tracks: migratedConfig.tracks ?? [],
    clipOrder: rowData.clipOrder,
    signature: getConfigSignature(resolvedConfig),
  };
};

export const loadTimelineJsonFromProvider = async (
  provider: DataProvider,
  timelineId: string,
): Promise<TimelineData> => {
  const [loadedTimeline, registry] = await Promise.all([
    provider.loadTimeline(timelineId),
    provider.loadAssetRegistry(timelineId),
  ]);

  return buildTimelineData(
    loadedTimeline.config,
    registry,
    (file) => provider.resolveAssetUrl(file),
    loadedTimeline.configVersion,
  );
};

export async function loadTranscript(
  provider: DataProvider,
  assetKey: string,
): Promise<TranscriptSegment[]> {
  const profile = await provider.loadAssetProfile?.(assetKey);
  return profile?.transcript?.segments ?? [];
}

export function getAssetColor(asset: string): string {
  return ASSET_COLORS[asset] ?? '#abb2bf';
}

import type {
  ResolvedTimelineConfig,
  TimelineClip,
  TimelineConfig,
  TrackDefinition,
} from '@/tools/video-editor/types';

export const TIMELINE_CLIP_FIELDS = [
  'id',
  'at',
  'track',
  'clipType',
  'asset',
  'from',
  'to',
  'speed',
  'hold',
  'volume',
  'x',
  'y',
  'width',
  'height',
  'cropTop',
  'cropBottom',
  'cropLeft',
  'cropRight',
  'opacity',
  'text',
  'entrance',
  'exit',
  'continuous',
  'transition',
  'effects',
] as const;

export type TimelineClipField = (typeof TIMELINE_CLIP_FIELDS)[number];

export const TRACK_DEFINITION_FIELDS = [
  'id',
  'kind',
  'label',
  'scale',
  'fit',
  'opacity',
  'blendMode',
] as const;

export type TrackDefinitionField = (typeof TRACK_DEFINITION_FIELDS)[number];

export const serializeClipForDisk = (clip: ResolvedTimelineConfig['clips'][number]): TimelineClip => {
  const serializedClip: Partial<Record<TimelineClipField, TimelineClip[TimelineClipField]>> = {
    id: clip.id,
    at: clip.at,
    track: clip.track,
  };

  if (clip.asset !== undefined) {
    serializedClip.asset = clip.asset;
  }

  for (const field of TIMELINE_CLIP_FIELDS) {
    if (field in serializedClip) {
      continue;
    }

    const value = clip[field];
    if (value !== undefined) {
      serializedClip[field] = value;
    }
  }

  return serializedClip as TimelineClip;
};

export const serializeTrackForDisk = (track: TrackDefinition): TrackDefinition => {
  const serializedTrack: Partial<Record<TrackDefinitionField, TrackDefinition[TrackDefinitionField]>> = {
    id: track.id,
    kind: track.kind,
    label: track.label,
  };

  for (const field of TRACK_DEFINITION_FIELDS) {
    if (field in serializedTrack) {
      continue;
    }

    const value = track[field];
    if (value !== undefined) {
      serializedTrack[field] = value;
    }
  }

  return serializedTrack as TrackDefinition;
};

const ALLOWED_TOP_LEVEL_KEYS = new Set(['output', 'clips', 'tracks', 'customEffects']);

export const validateSerializedConfig = (config: TimelineConfig): void => {
  const topLevelKeys = Object.keys(config);
  const unexpectedKeys = topLevelKeys.filter((key) => !ALLOWED_TOP_LEVEL_KEYS.has(key));
  if (unexpectedKeys.length > 0) {
    throw new Error(`Serialized timeline has unexpected top-level keys: ${unexpectedKeys.join(', ')}`);
  }

  const allowedClipKeys = new Set<string>(TIMELINE_CLIP_FIELDS);
  for (const clip of config.clips) {
    const invalidClipKeys = Object.keys(clip).filter((key) => !allowedClipKeys.has(key));
    if (invalidClipKeys.length > 0) {
      throw new Error(`Serialized clip '${clip.id}' has unexpected keys: ${invalidClipKeys.join(', ')}`);
    }
  }

  const allowedTrackKeys = new Set<string>(TRACK_DEFINITION_FIELDS);
  for (const track of config.tracks ?? []) {
    const invalidTrackKeys = Object.keys(track).filter((key) => !allowedTrackKeys.has(key));
    if (invalidTrackKeys.length > 0) {
      throw new Error(`Serialized track '${track.id}' has unexpected keys: ${invalidTrackKeys.join(', ')}`);
    }
  }
};

export const serializeForDisk = (
  resolved: ResolvedTimelineConfig,
  customEffects?: TimelineConfig['customEffects'],
): TimelineConfig => {
  const serialized: TimelineConfig = {
    output: { ...resolved.output },
    tracks: resolved.tracks.map(serializeTrackForDisk),
    clips: resolved.clips.map(serializeClipForDisk),
  };

  if (customEffects && Object.keys(customEffects).length > 0) {
    serialized.customEffects = customEffects;
  }

  validateSerializedConfig(serialized);
  return serialized;
};

